CREATE TRIGGER [dbo].[DefectProcess_History]ON [dbo].[DefectProcess]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.DefectProcessId IS NOT NULL AND d.DefectProcessId IS NULL THEN 'I' 		WHEN i.DefectProcessId IS NOT NULL AND d.DefectProcessId IS NOT NULL THEN 'U' 		WHEN i.DefectProcessId IS NULL AND d.DefectProcessId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.DefectProcessId = d.DefectProcessId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_DefectProcess([DefectProcessId], [DefectId], [ProcessId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [DefectProcessId], [DefectId], [ProcessId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_DefectProcess([DefectProcessId], [DefectId], [ProcessId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [DefectProcessId], [DefectId], [ProcessId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND